// ============================================
// SETUP ENTRADA v1.0 - uazapi
// ============================================
try {
    const body = $input.all()[0].json.body || $input.all()[0].json;

    const msg  = body.message || {};
    const chat = body.chat    || {};

    // Filtrar mensagens enviadas pelo próprio bot
    if (msg.fromMe === true || msg.fromMe === 'true') return [];
    if (msg.wasSentByApi === true) return [];

    // Ignorar grupos
    if (msg.isGroup === true || chat.wa_isGroup === true) return [];
    if ((msg.chatid || '').includes('@g.us')) return [];

    // Telefone
    const rawPhone = msg.sender_pn
        || msg.chatid
        || chat.wa_chatid
        || chat.phone
        || '';

    const phone = rawPhone
        .replace('@s.whatsapp.net', '')
        .replace('@c.us', '')
        .replace(/\D/g, '');

    if (!phone || phone.length < 10) return [];

    // Deteccao de comando admin (/pause ou /resume)
    const ADMIN_PHONE_CMD = '554598080945';
    const isAdmin = phone === ADMIN_PHONE_CMD || phone === ADMIN_PHONE_CMD.replace('55', '');
    if (isAdmin && messageText) {
        const cmdMatch = messageText.match(/^\/(pause|resume)\s+(\d{10,13})/i);
        if (cmdMatch) {
            return [{
                json: {
                    is_admin_command: true,
                    command: cmdMatch[1].toLowerCase(),
                    target_phone: cmdMatch[2].replace(/\D/g, ''),
                    client_id: phone,
                    channel: 'whatsapp',
                    timestamp: new Date().toISOString(),
                }
            }];
        }
    }


    // Nome
    const name = msg.senderName
        || chat.name
        || chat.wa_name
        || 'Cliente';

    // Tipo e conteúdo
    const msgType      = msg.type        || msg.messageType || '';
    const mediaType_raw = msg.mediaType  || '';

    let mediaType   = 'text';
    let messageText = '';

    if (msgType === 'audio' || msgType === 'ptt' || mediaType_raw === 'audio') {
        mediaType   = 'audio';
        messageText = '[ÁUDIO]';
    } else if (msgType === 'image' || mediaType_raw === 'image') {
        mediaType   = 'image';
        messageText = msg.content?.caption || msg.text || '[IMAGEM]';
    } else if (msgType === 'video' || mediaType_raw === 'video') {
        mediaType   = 'video';
        messageText = msg.content?.caption || msg.text || '[VÍDEO]';
    } else if (msgType === 'document' || mediaType_raw === 'document') {
        mediaType   = 'document';
        messageText = msg.content?.caption || msg.text || '[DOCUMENTO]';
    } else if (msgType === 'sticker') {
        mediaType   = 'sticker';
        messageText = '[STICKER]';
    } else {
        messageText = msg.text
            || msg.content?.text
            || msg.content?.conversation
            || '';
    }

    if (!messageText) return [];

    const provider_message_id = msg.messageid || msg.id || null;
    const queueKey = `msg_queue:${phone}`;
    const msgId    = $execution.id + '-' + Math.random().toString(36).substr(2, 9);

    const messageData = JSON.stringify({
        text:               messageText,
        name,
        ts:                 Date.now(),
        msg_id:             msgId,
        provider_message_id: provider_message_id || null,
    });

    return [{
        json: {
            client_id:           phone,
            client_name:         name,
            message_text:        messageText,
            media_type:          mediaType,
            provider_message_id: provider_message_id,
            channel:             'whatsapp',
            timestamp:           new Date().toISOString(),
            message_id:          msgId,
            session_id:          `tropicana_${phone}`,
            queue_key:           queueKey,
            message_data:        messageData,
            wa_provider:         'uazapi',
        }
    }];

} catch (err) {
    console.error('Setup Entrada uazapi:', err.message);
    return [];
}

// ============================================
// AGRUPADOR: PROCESSAR FILA v7.3 - ROBUSTO
// Compatível com Upstash via HTTP Request (result / body.result / data.result)
// ============================================

try {
  const setupData = $('Setup Entrada').first().json;

  // O HTTP Request do n8n pode retornar direto ou dentro de "body" (Full Response)
  const raw = $json;
  const payload =
    (raw && typeof raw === 'object' && raw.body && typeof raw.body === 'object') ? raw.body :
    (raw && typeof raw === 'object' && raw.data && typeof raw.data === 'object') ? raw.data :
    raw;

  // Upstash LRANGE normalmente vem em payload.result
  const resultArr =
    Array.isArray(payload?.result) ? payload.result :
    Array.isArray(raw?.result) ? raw.result :
    Array.isArray(raw?.body?.result) ? raw.body.result :
    Array.isArray(raw?.data?.result) ? raw.data.result :
    [];

  let messages = [];

  for (const item of resultArr) {
    // item pode vir como string JSON ("{...}") ou já como objeto
    if (item && typeof item === 'object') {
      // se já for objeto, tenta normalizar
      messages.push({
        text: item.text ?? item.message ?? String(item),
        name: item.name ?? setupData.client_name,
        ts: item.ts ?? Date.now(),
        msg_id: item.msg_id ?? setupData.message_id,
        provider_message_id: item.provider_message_id ?? setupData.provider_message_id
      });
      continue;
    }

    if (typeof item === 'string') {
      try {
        const parsed = JSON.parse(item);
        messages.push(parsed);
      } catch (e) {
        // fallback: se não for JSON, guarda como texto puro
        messages.push({
          text: item,
          name: setupData.client_name,
          ts: Date.now(),
          msg_id: setupData.message_id
        });
      }
    }
  }

  if (messages.length === 0) {
    // debug forte pra você enxergar o formato real
    console.log('Processar Fila DEBUG: raw keys=', Object.keys(raw || {}));
    console.log('Processar Fila DEBUG: payload keys=', Object.keys(payload || {}));
    console.log('Processar Fila DEBUG: resultArr=', resultArr);

    return { json: { skip: true, reason: 'no_messages' } };
  }

  // Ordenar por timestamp
  messages.sort((a, b) => (a.ts ?? 0) - (b.ts ?? 0));

  // Verificar dono da última mensagem (debounce/ownership)
  const lastMessage = messages[messages.length - 1];
  if (lastMessage.msg_id !== setupData.message_id) {
    return { json: { skip: true, reason: 'not_owner' } };
  }

  // Consolidar
  const consolidatedText = messages.map(m => m.text).join('\n');
  const clientName = messages[0].name || setupData.client_name;

  return {
    json: {
      skip: false,
      client_id: setupData.client_id,
      client_name: clientName,
      message_text: consolidatedText,
      channel: "whatsapp",
      timestamp: new Date().toISOString(),
      message_id: setupData.message_id,
      messages_count: messages.length,
      session_id: `tropicana_${setupData.client_id}`,
      queue_key: setupData.queue_key
    }
  };

} catch (error) {
  console.error('Processar Fila: Erro geral -', error.message);
  return { json: { skip: true, reason: 'error', error_message: error.message } };
}

// ============================================
// PROCESSAR RESPOSTA v11.0
// ============================================
try {
    const aiOutput = $json.output || $json.text || $json;
    const inputData = $('Processar Fila').first().json;

    let responseText = '';
    let escalateHuman = false;
    let intent = 'geral';
    let confidence = 0.5;
    let newOrderState = null;

    let rawText = typeof aiOutput === 'string' ? aiOutput : JSON.stringify(aiOutput);

    rawText = rawText
        .replace(/```json/gi, '')
        .replace(/```/gi, '')
        .trim();

    const jsonMatch = rawText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
        try {
            const parsed = JSON.parse(jsonMatch[0]);
            responseText  = parsed.response_text || '';
            escalateHuman = parsed.escalate_human || false;
            intent        = parsed.intent || 'geral';
            confidence    = parsed.confidence || 0.5;
            newOrderState = parsed.new_order_state || null;
        } catch (e) {
            const fallback = rawText.replace(/\{[\s\S]*\}/, '').trim();
            responseText = (fallback && fallback.length > 3) ? fallback : 'Desculpe, tive um problema interno. Pode repetir? \u{1F60A}';
        }
    } else {
        responseText = rawText;
    }

    if (!responseText || responseText.length < 3) {
        responseText = 'Desculpe, n\u00e3o consegui processar sua mensagem. Pode repetir? \u{1F60A}';
    }

    responseText = responseText
        .replace(/```json/gi, '')
        .replace(/```/g, '')
        .trim();

    // Gerar pedido_codigo aqui se fase = aguardando_confirmacao
    // Assim o codigo real aparece na mensagem enviada ao cliente
    if (newOrderState && newOrderState.phase === 'aguardando_confirmacao') {
        if (!newOrderState.pedido_codigo) {
            newOrderState.pedido_codigo = '#TRP' + String(Math.floor(Date.now() % 1000000)).padStart(6, '0');
        }
        const codigo = newOrderState.pedido_codigo;
        // Substituir qualquer variacao do placeholder pelo codigo real
        responseText = responseText
            .replace(/#TRP\[.*?\]/g, codigo)
            .replace(/#TRP\{\{.*?\}\}/g, codigo)
            .replace(/\{\{\s*pedido_codigo\s*\}\}/g, codigo)
            .replace(/\[c\u00f3digo\]/g, codigo)
            .replace(/\[codigo\]/g, codigo);
    }

    const clientId = inputData.client_id || '00';
    const distributedDelay = parseInt(clientId.slice(-2), 10) % 10;
    const waitSeconds = 2 + distributedDelay;

    return {
        json: {
            client_id:       inputData.client_id,
            client_name:     inputData.client_name,
            response_text:   responseText,
            escalate_human:  Boolean(escalateHuman),
            intent:          intent,
            confidence:      confidence,
            session_id:      inputData.session_id,
            timestamp:       new Date().toISOString(),
            wait_seconds:    waitSeconds,
            new_order_state: newOrderState ? JSON.stringify(newOrderState) : null
        }
    };

} catch (error) {
    console.error('Processar Resposta: Erro geral -', error.message);
    const inputData = $('Processar Fila').first().json;
    return {
        json: {
            client_id:       inputData.client_id,
            client_name:     inputData.client_name,
            response_text:   'Desculpe, tive um problema. Por favor, tente novamente.',
            escalate_human:  true,
            intent:          'error',
            confidence:      0,
            session_id:      inputData.session_id,
            timestamp:       new Date().toISOString(),
            wait_seconds:    3,
            new_order_state: null
        }
    };
}

