// ============================================
// PREPARAR CONTEXTO PEDIDO v3.0 - COM HORARIO
// ============================================
try {
    const filaData = $('Processar Fila').first().json;
    const redisResponse = $json;

    // ?? HORARIO DE PEDIDOS (BRT = UTC-3) ??
    const _now = new Date();
    const _brtMs = _now.getTime() - (3 * 60 * 60 * 1000);
    const _brt = new Date(_brtMs);
    const _totalMin = _brt.getUTCHours() * 60 + _brt.getUTCMinutes();
    const _janelas = [
        { inicio: 11 * 60,       fim: 15 * 60 + 45, label: '11h ás 15h45' },
        { inicio: 18 * 60,       fim: 21 * 60 + 45, label: '18h ás 21h45' },
    ];
    const aceitaPedidos = _janelas.some(j => _totalMin >= j.inicio && _totalMin <= j.fim);
    let proximaJanela = '';
    if (!aceitaPedidos) {
        for (const j of _janelas) {
            if (_totalMin < j.inicio) { proximaJanela = j.label; break; }
        }
        if (!proximaJanela) proximaJanela = _janelas[0].label + ' (amanhã)';
    }

    // ?? ESTADO DO PEDIDO ??
    let orderState = null;
    try {
        if (redisResponse && redisResponse.result && redisResponse.result !== null) {
            orderState = JSON.parse(redisResponse.result);
        }
    } catch(e) { orderState = null; }

    if (!orderState) {
        orderState = {
            phase: "idle",
            items: [],
            nome_cliente: null,
            endereco: null,
            complemento: null,
            bairro: null,
            forma_pagamento: null,
            troco_para: null,
            total: 0,
            confirmado: false
        };
    }

    let orderSummary = "";
    if (orderState.phase === "idle") {
        orderSummary = "Nenhum pedido em andamento.";
    } else if (orderState.phase === "coletando") {
        const itensList = orderState.items.length > 0
            ? orderState.items.map(i => `${i.nome} x${i.quantidade}`).join(", ")
            : "nenhum ainda";
        orderSummary = `PEDIDO EM ANDAMENTO (coletando informações):\n` +
            `- Itens: ${itensList}\n` +
            `- Nome: ${orderState.nome_cliente || "não informado"}\n` +
            `- Endereço: ${orderState.endereco || "não informado"}\n` +
            `- Complemento: ${orderState.complemento || "não informado"}\n` +
            `- Bairro: ${orderState.bairro || "não informado"}\n` +
            `- Pagamento: ${orderState.forma_pagamento || "não informado"}\n` +
            `- Troco: ${orderState.troco_para ? "R$ " + orderState.troco_para : "não necessário"}\n` +
            `- Total parcial: R$ ${orderState.total}`;
    } else if (orderState.phase === "aguardando_confirmacao") {
        const itensList = orderState.items
            .map(i => `  . ${i.nome} x${i.quantidade} - R$ ${i.preco_total}`)
            .join("\n");
        orderSummary = `PEDIDO AGUARDANDO CONFIRMAÇÃO DO CLIENTE:\n` +
            `${itensList}\n` +
            `- Nome: ${orderState.nome_cliente}\n` +
            `- Endereço: ${orderState.endereco}${orderState.complemento ? ", " + orderState.complemento : ""} - ${orderState.bairro}\n` +
            `- Pagamento: ${orderState.forma_pagamento}\n` +
            `${orderState.troco_para ? "- Troco para: R$ " + orderState.troco_para + "\n" : ""}` +
            `- TOTAL: R$ ${orderState.total}`;
    } else if (orderState.phase === "finalizado") {
        orderSummary = "Pedido finalizado e confirmado pelo cliente.";
    }

    return [{
        json: {
            ...filaData,
            order_state: JSON.stringify(orderState),
            order_summary: orderSummary,
            order_phase: orderState.phase,
            aceita_pedidos: aceitaPedidos,
            proxima_janela: proximaJanela,
        }
    }];

} catch (error) {
    console.error("Preparar Contexto Pedido: Erro -", error.message);
    const filaData = $('Processar Fila').first().json;
    return [{
        json: {
            ...filaData,
            order_state: JSON.stringify({ phase: "idle", items: [], total: 0, confirmado: false }),
            order_summary: "Nenhum pedido em andamento.",
            order_phase: "idle",
            aceita_pedidos: true,
            proxima_janela: "",
        }
    }];
}

// ============================================
// PREPARAR SALVAR PEDIDO v3.0 - injeta client_name e client_id
// ============================================
try {
    const responseData = $json;

    if (responseData.new_order_state) {
        const clientId = responseData.client_id;
        let stateStr = typeof responseData.new_order_state === 'string'
            ? responseData.new_order_state
            : JSON.stringify(responseData.new_order_state);

        try {
            const stateObj = JSON.parse(stateStr);

            // Gerar pedido_codigo no n8n (nunca deixar o AI gerar)
            if (stateObj.phase === 'aguardando_confirmacao' && !stateObj.pedido_codigo) {
                stateObj.pedido_codigo = '#TRP' + String(Math.floor(Date.now() % 1000000)).padStart(6, '0');
            }

            // Sempre injetar nome do cliente se o AI não incluiu
            if (!stateObj.nome_cliente && responseData.client_name) {
                stateObj.nome_cliente = responseData.client_name;
            }

            stateStr = JSON.stringify(stateObj);
        } catch(e) {}

        return [{
            json: {
                ...responseData,
                redis_key: `pedido_state:${clientId}`,
                redis_value: stateStr,
                redis_ttl: 7200
            }
        }];
    }

    return [{
        json: {
            ...responseData,
            redis_key: `pedido_noop`,
            redis_value: '{}',
            redis_ttl: 7200
        }
    }];
} catch(error) {
    console.error('Preparar Salvar Pedido: Erro -', error.message);
    return [{ json: $json }];
}

// ============================================
// REDIS: SALVAR ESTADO PEDIDO v3.0
// Não salva se não houver mudança de estado
// ============================================
const key = $json.redis_key || '';
const value = $json.redis_value || '{}';
const ttl = $json.redis_ttl || 7200;

// Não salvar se for noop
if (!key || key === 'pedido_noop') {
    return [{
        json: {
            client_id: $json.client_id,
            client_name: $json.client_name,
            response_text: $json.response_text,
            escalate_human: $json.escalate_human,
            intent: $json.intent,
            confidence: $json.confidence,
            session_id: $json.session_id,
            timestamp: $json.timestamp,
            wait_seconds: $json.wait_seconds,
            new_order_state: $json.new_order_state
        }
    }];
}

try {
    const encodedValue = encodeURIComponent(value);
    await this.helpers.httpRequest({
        method: 'POST',
        url: `https://peaceful-sailfish-14074.upstash.io/set/${key}/${encodedValue}/EX/${ttl}`,
        headers: {
            'Authorization': 'Bearer ATb6AAIncDFkNzcxNmI2MjYwMzc0OWIyYTE4Yzk1YjA4NjZkZDk2ZXAxMTQwNzQ'
        }
    });
} catch(e) {
    console.error('Redis save error:', e.message);
}

return [{
    json: {
        client_id: $json.client_id,
        client_name: $json.client_name,
        response_text: $json.response_text,
        escalate_human: $json.escalate_human,
        intent: $json.intent,
        confidence: $json.confidence,
        session_id: $json.session_id,
        timestamp: $json.timestamp,
        wait_seconds: $json.wait_seconds,
        new_order_state: $json.new_order_state
    }
}];

// ============================================
// NOTIFICAR PEDIDO v3.0 - com taxa de entrega
// ============================================
const responseData = $('Processar Resposta').first().json;
const rawState = responseData.new_order_state;

if (!rawState) {
  return { json: { ...responseData, admin_message: null } };
}

let order;
try {
  order = typeof rawState === 'string' ? JSON.parse(rawState) : rawState;
} catch(e) {
  return { json: { ...responseData, admin_message: null } };
}

if (!order || !order.items) {
  return { json: { ...responseData, admin_message: null } };
}

const codigo = order.pedido_codigo || '#TRP' + Date.now().toString().slice(-6);

const itens = order.items.map(i => {
  let linha = '. ' + i.nome + ' x' + i.quantidade + ' - R$ ' + (i.preco_total || 0).toFixed(2);
  if (i.detalhes?.sabores?.length)      linha += '\n  Sabores: ' + i.detalhes.sabores.join(', ');
  if (i.detalhes?.complementos?.length) linha += '\n  Complementos: ' + i.detalhes.complementos.join(', ');
  if (i.detalhes?.acompanhamento)       linha += '\n  Acompanhamento: ' + i.detalhes.acompanhamento;
  if (i.detalhes?.cobertura)            linha += '\n  Cobertura: ' + i.detalhes.cobertura;
  if (i.detalhes?.fruta)                linha += '\n  Fruta: ' + i.detalhes.fruta;
  return linha;
}).join('\n');

const entrega = order.bairro
  ? 'Delivery\n📍 ' + order.endereco + ', ' + order.bairro + (order.complemento ? ' - ' + order.complemento : '')
  : 'Retirada no balcão';

const taxa = order.taxa_entrega && order.taxa_entrega > 0
  ? '*Taxa de entrega:* R$ ' + parseFloat(order.taxa_entrega).toFixed(2) +
    (order.distancia_km ? ' (' + order.distancia_km + ' km)' : '') + '\n'
  : '';

const pagamento = '*Pagamento:* ' + (order.forma_pagamento || '-') + '\n' +
  (order.troco_para ? '*Troco para:* R$ ' + order.troco_para + '\n' : '');

const adminMessage =
  '🔔 *NOVO PEDIDO CONFIRMADO*\n\n' +
  '🏷️ *Código:* ' + codigo + '\n' +
  '👤 *Cliente:* ' + responseData.client_name + '\n' +
  '📞 *Telefone:* ' + responseData.client_id + '\n\n' +
  '*Itens:*\n' + itens + '\n\n' +
  '*Entrega:* ' + entrega + '\n' +
  taxa +
  pagamento +
  '\n*Total: R$ ' + (order.total || 0).toFixed(2) + '*';

return {
  json: {
    ...responseData,
    admin_message: adminMessage
  }
};

// ============================================
// VERIFICAR PEDIDO CONFIRMADO v2.0 - JSON parse seguro
// ============================================
try {
    const responseData = $('Processar Resposta').first().json;
    const rawState = responseData.new_order_state;

    if (!rawState) {
        return { json: { ...responseData, is_confirmed: false } };
    }

    let order;
    try {
        order = typeof rawState === 'string' ? JSON.parse(rawState) : rawState;
    } catch(e) {
        return { json: { ...responseData, is_confirmed: false } };
    }

    const isConfirmed = order && order.phase === 'finalizado' && order.confirmado === true;

    return {
        json: {
            ...responseData,
            is_confirmed: isConfirmed,
            admin_message: $json.admin_message || null
        }
    };
} catch(err) {
    console.error('Verificar Pedido Confirmado:', err.message);
    return { json: { ...$json, is_confirmed: false } };
}

