const https = require('https');

const TENANT_ID = 'demo_tenant';
const API_URL = 'https://pedai-rho.vercel.app/api/menu/' + TENANT_ID;

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }
        catch (e) { reject(new Error('JSON inválido: ' + data.substring(0, 200))); }
      });
    }).on('error', reject);
  });
}

try {
  const res = await httpsGet(API_URL);

  if (res.status !== 200) {
    return 'Erro ao consultar cardápio: HTTP ' + res.status;
  }

  const { categories } = res.body;

  if (!categories || categories.length === 0) {
    return 'Cardápio não disponível no momento.';
  }

  let resposta = 'CARDÁPIO:\n\n';

  for (const cat of categories) {
    resposta += cat.name.toUpperCase() + ':\n';
    for (const item of cat.items) {
      if (!item.available) continue;
      resposta += '. ' + item.name + ' - R$ ' + parseFloat(item.price).toFixed(2);
      if (item.description) resposta += '\n  ' + item.description;
      resposta += '\n';
    }
    resposta += '\n';
  }

  return resposta.trim();

} catch (err) {
  return 'Erro ao consultar cardápio: ' + err.message;
}

