const https = require('https');

const TENANT_ID = 'demo_tenant';
const API_URL = 'https://pedai-rho.vercel.app/api/settings/' + TENANT_ID;

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }
        catch (e) { reject(new Error('JSON inválido: ' + data.substring(0, 200))); }
      });
    }).on('error', reject);
  });
}

const bairroCliente = (typeof query !== 'undefined' ? query : '').toString().trim().toLowerCase();

if (!bairroCliente) {
  return 'Bairro não informado. Solicite o bairro ao cliente.';
}

try {
  const res = await httpsGet(API_URL);

  if (res.status !== 200) {
    return 'Erro ao consultar configurações: HTTP ' + res.status;
  }

  const { settings } = res.body;
  const zones = settings && settings.deliveryZones ? settings.deliveryZones : [];

  if (zones.length === 0) {
    return 'Nenhuma zona de entrega configurada. Informe o cliente que a entrega não está disponível no momento.';
  }

  const zona = zones.find(z => z.neighborhood.toLowerCase() === bairroCliente);

  if (!zona) {
    // Tenta busca parcial
    const zonaPartial = zones.find(z =>
      z.neighborhood.toLowerCase().includes(bairroCliente) ||
      bairroCliente.includes(z.neighborhood.toLowerCase())
    );

    if (zonaPartial) {
      return JSON.stringify({
        bairro: zonaPartial.neighborhood,
        taxa_entrega: zonaPartial.fee,
        bairro_confirmado: zonaPartial.neighborhood
      });
    }

    const bairrosDisponiveis = zones.map(z => z.neighborhood).join(', ');
    return 'Bairro "' + bairroCliente + '" não encontrado nas zonas de entrega. Bairros disponíveis: ' + bairrosDisponiveis + '. Peça ao cliente para confirmar o bairro ou ofereça retirada no local.';
  }

  return JSON.stringify({
    bairro: zona.neighborhood,
    taxa_entrega: zona.fee,
    bairro_confirmado: zona.neighborhood
  });

} catch (err) {
  return 'Erro ao calcular taxa de entrega: ' + err.message;
}

