const https = require('https');

const TENANT_ID = 'demo_tenant';
const API_URL = 'https://pedai-rho.vercel.app/api/orders';

const responseData = $json;
let order;
try {
  const rawState = responseData.new_order_state || responseData.order_state;
  order = typeof rawState === 'string' ? JSON.parse(rawState) : rawState;
} catch(e) {
  return [{ json: { ...responseData, api_order_error: 'Falha ao parsear order state' } }];
}

if (!order || !order.items || order.items.length === 0) {
  return [{ json: { ...responseData, api_order_error: 'Pedido sem itens' } }];
}

const payload = {
  tenantId: TENANT_ID,
  channel: 'WHATSAPP',
  type: order.bairro ? 'DELIVERY' : 'PICKUP',
  customerName: order.nome_cliente || responseData.client_name || '',
  customerPhone: responseData.client_id || '',
  address: order.endereco || '',
  neighborhood: order.bairro || '',
  deliveryFee: parseFloat(order.taxa_entrega) || 0,
  paymentMethod: order.forma_pagamento || '',
  items: order.items.map(i => ({
    name: i.nome,
    quantity: i.quantidade || 1,
    unitPrice: i.preco_unitario || (i.preco_total / (i.quantidade || 1)),
    total: i.preco_total || 0
  }))
};

function httpsPost(url, body) {
  return new Promise((resolve, reject) => {
    const bodyStr = JSON.stringify(body);
    const urlObj = new URL(url);
    const opts = {
      hostname: urlObj.hostname,
      path: urlObj.pathname,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) }
    };
    const req = https.request(opts, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }
        catch (e) { resolve({ status: res.statusCode, body: data }); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

try {
  const res = await httpsPost(API_URL, payload);
  return [{ json: { ...responseData, api_order_status: res.status, api_order_response: res.body } }];
} catch (err) {
  return [{ json: { ...responseData, api_order_error: err.message } }];
}
